--- 请求升星
---@param type number 操作类型 1：一键升星
function LxHeroHandler:HeroUpStarReq(upStarArgs,type)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroUpStarReq)
    local args = proto.args
    for i,v in ipairs(upStarArgs) do
        local upStarArg = args:add()
        upStarArg.id = v.id
        for idx,val in ipairs(v.appoints) do
            upStarArg.appoints:append(val)
        end
        for idx,val in ipairs(v.ranges) do
            upStarArg.ranges:append(val)
        end
        local rangeItems = upStarArg.rangeItems
        for idx,val in ipairs(v.rangeItems) do
            local rangeItem = rangeItems:add()
            rangeItem.refId = val.refId
            rangeItem.num = val.num
        end
    end
    if type and type > 0 then
        proto.type = type
    end
    SendMessage(LxProtoIds.HeroUpStarReq, proto)
end

--- 英雄遣返
---@param ids table<string> 遣返的英雄id列表
---@param item table 遣返的道具列表
function LxHeroHandler:HeroSacrificeReq(ids, item)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroSacrificeReq)
    for i,v in ipairs(ids) do
        proto.ids:append(v)
    end

    local pitem = proto.item
    for i,v in ipairs(item) do
        local kv = pitem:add()
        kv.key = v.key
        kv.value = v.value
    end
    SendMessage(LxProtoIds.HeroSacrificeReq, proto)
end


