--- 请求升级返回
function LxHeroHandler:OnHeroUpLevelResp(pb)
    if pb.hero then
        local pbHero = pb.hero
        ---@type LxHeroObj
        local oldHeroObj = ModuleCenter.Hero:GetHero(tostring(pbHero.id))
        local oldPower = oldHeroObj.power
        local oldAttrList = {}
        for i,v in ipairs(oldHeroObj.attrList) do
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(oldAttrList,v)
            end
        end

        ---@type LxHeroObj
        local heroObj = ModuleCenter.Hero:AddHero(pbHero)
        CtrlCenter.Hero:PrintHeroObjAttrMap(heroObj,"升级后数据")

        local newAttrList = {}
        for i,v in ipairs(heroObj.attrList) do
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(newAttrList,v)
            end
        end
        local newPower = heroObj.power
        CtrlCenter.Hero:OpenUpInfo(oldPower,newPower,oldAttrList,newAttrList,HeroOptTypeEnum.UpLevel)

        FireEvent(EventNames.HERO_TRAIN_MAIN,{
            optType = HeroTrainTypeEnum.UpLevel,
            heroObj = heroObj,
        })

        FireEvent(EventNames.REFRESH_HERO_ALLRP,{
            refreshWay = LxProtoIds.HeroUpLevelResp,
        })
        FireEvent(EventNames.HERO_INFO_CHANGE)
    end
end


