--- 请求升星返回
function LxHeroHandler:OnHeroUpStarResp(pb)
    local upStars = pb.upStars
    local isAutoUpStar = pb.type == 1

    if isAutoUpStar then    --- 一键升星
        local showReward = {}
        local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
        local changeHeroIdMap = ModuleCenter.Hero:SetHeroes(upStars)
        for i, v in ipairs(upStars) do
            local _t = {}
            _t.type = ThingType.Hero
            _t.refId = checknumber(v.refId)
            _t.star = v.star
            _t.num = 1
            table.insert(showReward, _t)
        end
        for _, v in ipairs(things.rewardList) do
            table.insert(showReward, v)
        end
        ShowPanel(UiNames.HeroBatchUpStarSuc, {prizes = showReward})
    else
        local firstHeroId
        if not isAutoUpStar then
            local firstHero = upStars[1]
            if firstHero then
                firstHeroId = tostring(firstHero.id)
            end
        end

        ---@type LxHeroObj
        local oldHeroObj
        if firstHeroId then
            oldHeroObj = ModuleCenter.Hero:GetHero(firstHeroId)
        end
        local changeHeroIdMap = ModuleCenter.Hero:SetHeroes(upStars)
        if isAutoUpStar then return end
        if not oldHeroObj then return end

        local oldHeroStar = oldHeroObj.star
        local oldPower = oldHeroObj.power
        local oldAttrList = {}
        local recordOldAttrMap = {}
        for k,v in pairs(oldHeroObj.attrMap) do
            recordOldAttrMap[k] = v.value
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(oldAttrList,v)
            end
        end

        ---@type LxHeroObj
        local newHeroObj = ModuleCenter.Hero:GetHero(firstHeroId)
        if not newHeroObj then return end

        ShowPanel(UiNames.HeroUpStarSucNew,{heroObj = newHeroObj})

        FireEvent(EventNames.HERO_TRAIN_MAIN,{
            optType = HeroTrainTypeEnum.UpStar,
            heroObj = newHeroObj,
        })
        local newAttrList = {}
        for i,v in ipairs(newHeroObj.attrList) do
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(newAttrList,v)
            end
        end

        FireEvent(EventNames.REFRESH_HERO_ALLRP,{
            refreshWay = LxProtoIds.HeroUpStarResp,
        })

        local typeEnum = HeroOptTypeEnum.UpStar
        local newPower = newHeroObj.power
        --if newHeroObj.star - oldHeroStar < 1 then
        --    CtrlCenter.Hero:OpenUpInfo(oldPower,newPower,oldAttrList,newAttrList,typeEnum)
        --end
        CtrlCenter.Hero:OpenUpInfo(oldPower,newPower,oldAttrList,newAttrList,typeEnum)
    end
    FireEvent(EventNames.HERO_INFO_CHANGE)
    CtrlCenter.City:RefreshHeroUpStarInfo()
end


