--- 超凡英雄绑定/解绑
function LxHeroHandler:OnHeroLinkResp(pb)
    local heroModule = ModuleCenter.Hero
    local pbHero = pb.hero
    local oldHero = heroModule:GetHero(pbHero.id)
    local oldPower = oldHero.power
    local oldAttrList = oldHero.attrList
    local oldHeroObj = {
        id = oldHero.id,
        refId = oldHero.refId,
        level = oldHero.level,
        star = oldHero.star,
        grade = oldHero.grade,
        quality = oldHero.quality,
        power = oldPower,
        maxStar = oldHero.maxStar,
        lock = oldHero.lock,
        attrList = oldAttrList,
        attrMap = oldHero.attrMap,
        shareLevel = oldHero.shareLevel,
        shareGrade = oldHero.shareGrade,
        skinId = oldHero.skinId,
        link = oldHero.link,
        breakLevel = oldHero.breakLevel,
        groupLevel = oldHero.groupLevel,
        groupStar = oldHero.groupStar,
    }

    local hero = heroModule:AddHero(pbHero)
    local targetHero = heroModule:AddHero(pb.targetHero)
    local isLinkSuc = hero.link == targetHero.id
    local sendTargetHero = nil
    if isLinkSuc then
        sendTargetHero = targetHero
        ShowPanel(UiNames.HeroLinkSuc,{
            heroObj = oldHeroObj,
            targetObj = hero,
            linkHeroObj = targetHero,
        })
    else
        ShowPanel(UiNames.HeroUnLinkSuc,{
            heroObj = oldHeroObj,
            targetObj = hero,
            unLinkHeroObj = targetHero,
        })
    end

    CtrlCenter.Hero:OpenUpInfo(oldPower,hero.power,oldAttrList,hero.attrList,HeroOptTypeEnum.Link)

    FireEvent(EventNames.HERO_LINK_RESP,{
        hero = hero,
        targetHero = sendTargetHero,
        isLinkSuc = isLinkSuc,
    })

    FireEvent(EventNames.HERO_TRAIN_MAIN,{
        optType = HeroTrainTypeEnum.Link,
        heroObj = hero,
    })
end

