function LxHeroHandler:OnHeroLoveRewardResp(pb)
    local refId = pb.refId
    if refId and refId > 0 then
        local heroTableObj = ModuleCenter.Hero:GetHeroTableObj(refId)
        if heroTableObj then
            heroTableObj.goodReward = true
        end
    end

    ---@type LxThingsInfo 获得的奖励
    local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroLoveReward, things)

    FireEvent(EventNames.UPDATE_HEROBOOK_INFO,{
        state = HeroLoveTypeEnum.LoveReward,
    })

    FireEvent(EventNames.REFRESH_HERO_ALLRP,{
        refreshWay = LxProtoIds.HeroLoveRewardResp,
    })
end

--- 赠送好感礼物
function LxHeroHandler:OnHeroGiveGiftResp(pb)
    --[[local heroModule = ModuleCenter.Hero

    local heroCtrl = CtrlCenter.Hero

    local oAllLevel = heroCtrl:GetHeroTableAllLoveLevel()
    local heroTable = pb.heroTable
    local heroRefId = heroTable.refId
    ---@type LxHeroTableObj
    local oHeroTableObj = heroModule:GetHeroTableObj(heroRefId)
    local oldLoveLv = oHeroTableObj and oHeroTableObj.loveLevel or 0

    ---@type LxHeroTableObj
    local obj = heroModule:AddHeroTableObj(heroTable)
    local nAllLevel = heroCtrl:GetHeroTableAllLoveLevel()

    local callBack
    if nAllLevel > oAllLevel then
        callBack = function()
            ShowPanel(UiNames.HeroLoveUpLevelTips,{
                LoveUpLevelEnum = 0,
                curLevel = oAllLevel,
                nextLevel = nAllLevel,
            })
        end
    end

    ---@type LxThingsInfo 获得的奖励
    local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)

    local showThings = false
    if oldLoveLv and oldLoveLv < obj.loveLevel then
        showThings = true
        ShowPanel(UiNames.HeroLoveUpLevelTips,{
            LoveUpLevelEnum = 1,
            curLevel = oldLoveLv,
            nextLevel = obj.loveLevel,
            heroRefId = heroRefId,
            thingsInfo = things,
            callBack = callBack,
        })
    end
    if not showThings then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroGiveGift, things)
    end]]


    local showFunc
    local info = self:DisposeHeroTable(pb)
    if info.openRewardFunc then
        showFunc = info.openRewardFunc
    elseif info.openUpLvFunc then
        showFunc = info.openUpLvFunc
    end


    FireEvent(EventNames.UPDATE_HEROBOOK_INFO,{
        state = HeroLoveTypeEnum.GiveGift,
        heroTableObj = info.obj,
        showUpLv = info.showUpLv,
        showFunc = showFunc,
    })

    FireEvent(EventNames.REFRESH_HERO_ALLRP,{
        refreshWay = LxProtoIds.HeroGiveGiftResp,
    })
end

--- 互动操作
function LxHeroHandler:OnHeroTouchResp(pb)
--[[    local heroModule = ModuleCenter.Hero

    local heroTable = pb.heroTable
    local heroRefId = heroTable.refId
    ---@type LxHeroTableObj
    local oHeroTableObj = heroModule:GetHeroTableObj(heroRefId)
    local obj = heroModule:AddHeroTableObj(pb.heroTable)
    heroModule:SetRoleTouchCount(pb.roleTouchCount)

    ---@type LxThingsInfo 获得的奖励
    local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroGiveGift, things)]]


    local info = self:DisposeHeroTable(pb)
    local func = function()
        if info.openRewardFunc then
            info.openRewardFunc()
        elseif info.openUpLvFunc then
            info.openUpLvFunc()
        end
    end

    local showFunc
    local doReward = false
    if pb.dropInfo then
        ---@type LxThingsInfo 互动掉落奖励
        local dropInfo = ModuleCenter.Common:NewThingsInfo(pb.dropInfo)
        local rewardList = dropInfo.rewardList
        if rewardList and #rewardList > 0 then
            doReward = true
            showFunc = function()
                FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroGiveGift, dropInfo,nil, {
                    callBack = func,
                })
            end
        end
    end
    if not doReward then
        showFunc = func
    end




    FireEvent(EventNames.UPDATE_HEROBOOK_INFO,{
        state = HeroLoveTypeEnum.Touch,
        heroTableObj = info.obj,
        showUpLv = info.showUpLv,
        showFunc = showFunc,
    })

    FireEvent(EventNames.REFRESH_HERO_ALLRP,{
        refreshWay = LxProtoIds.HeroTouchResp,
    })
end

function LxHeroHandler:DisposeHeroTable(pb)
    local heroModule = ModuleCenter.Hero
    local heroCtrl = CtrlCenter.Hero

    local oAllLevel = heroCtrl:GetHeroTableAllLoveLevel()
    local heroTable = pb.heroTable
    local heroRefId = heroTable.refId
    ---@type LxHeroTableObj
    local oHeroTableObj = heroModule:GetHeroTableObj(heroRefId)
    local oldLoveLv = oHeroTableObj and oHeroTableObj.loveLevel or 0

    ---@type LxHeroTableObj
    local obj = heroModule:AddHeroTableObj(heroTable)
    local nAllLevel = heroCtrl:GetHeroTableAllLoveLevel()

    local checkAniFunc
    local panelKey = UiNames.HeroLoveUpLevelTips
    local callBack
    if nAllLevel > oAllLevel then
        callBack = function()
            local data = {
                LoveUpLevelEnum = 0,
                curLevel = oAllLevel,
                nextLevel = nAllLevel,
                checkAniFunc = checkAniFunc,
            }
            if IsOpenPanel(panelKey) then
                RefreshPanel(panelKey,data)
            else
                ShowPanel(panelKey,data)
            end
        end
    end

    local info = {
        obj = obj,
    }

    ---@type LxThingsInfo 获得的奖励
    local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    local showUpLv = false
    if oldLoveLv and oldLoveLv < obj.loveLevel then
        showUpLv = true

        --checkAniFunc = function()
        --    --FireEvent(EventNames.SHOW_UPLOVELV_ANI)
        --end

        info.openUpLvFunc = function()
            ShowPanel(panelKey,{
                LoveUpLevelEnum = 1,
                curLevel = oldLoveLv,
                nextLevel = obj.loveLevel,
                heroRefId = heroRefId,
                thingsInfo = things,
                callBack = callBack,
            })
        end
    end
    if not showUpLv then
        info.openRewardFunc = function()
            --- 如果只展示奖励，判断是否存在总好感度升级
            FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroGiveGift, things,nil,{
                callBack = callBack,
            })
        end
    end
    info.showUpLv = showUpLv
    return info
end

function LxHeroHandler:OnHeroRollbackResp(pb)
    ModuleCenter.Hero:AddHero(pb.hero)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroRebirth, pb.thingsInfo)
    FireEvent(EventNames.HERO_INFO_CHANGE)
    CtrlCenter.City:RefreshHeroUpStarInfo()
end



function LxHeroHandler:OnEquipExcStrengthResp(pb)
    if pb.hero then
        local pbHero = pb.hero
        ---@type LxHeroObj
        local oldHeroObj = ModuleCenter.Hero:GetHero(tostring(pbHero.id))
        local oldPower = oldHeroObj.power
        local oldAttrList = {}
        for i,v in ipairs(oldHeroObj.attrList) do
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(oldAttrList,v)
            end
        end

        ---@type LxHeroObj
        local heroObj = ModuleCenter.Hero:AddHero(pbHero)
        CtrlCenter.Hero:PrintHeroObjAttrMap(heroObj,"升级后数据")

        local newAttrList = {}
        for i,v in ipairs(heroObj.attrList) do
            if LxDataHelper.GetCombatAttributeIsShow(v.refId) then
                table.insert(newAttrList,v)
            end
        end
        local newPower = heroObj.power
        CtrlCenter.Hero:OpenUpInfo(oldPower,newPower,oldAttrList,newAttrList,HeroOptTypeEnum.UpLevel)

        FireEvent(EventNames.HERO_TRAIN_MAIN,{
            optType = HeroTrainTypeEnum.EquipExc,
            heroObj = heroObj,
        })

    end
    FireEvent(EventNames.HERO_EQUIP_EXC_CHANGE)
end

return LxHeroHandler